// Given CFG G1 with start symbol S1 and G2 with start symbol S2
// Construct CFG G for L(G1) ∪ L(G2)

ALGORITHM UnionCFG(G1, G2):
BEGIN
 // Create new start symbol
 S_new = new_nonterminal()

 // New production: S_new → S1 | S2
 add_production(S_new, S1)
 add_production(S_new, S2)

 // Copy all productions from G1
 FOR each production p in G1.productions:
 add_production(p)

 // Copy all productions from G2
 FOR each production p in G2.productions:
 add_production(p)

 RETURN new_grammar(S_new, productions)
END

// Given CFG G1 with start symbol S1 and G2 with start symbol S2
// Construct CFG G for L(G1)L(G2)

ALGORITHM ConcatenationCFG(G1, G2):
BEGIN
 // Create new start symbol
 S_new = new_nonterminal()

 // New production: S_new → S1 S2
 add_production(S_new, concatenate(S1, S2))

 // Copy all productions from G1
 FOR each production p in G1.productions:
 add_production(p)

 // Copy all productions from G2
 FOR each production p in G2.productions:
 add_production(p)

 RETURN new_grammar(S_new, productions)
END

// Given CFG G with start symbol S
// Construct CFG for L*

ALGORITHM KleeneStarCFG(G):
BEGIN
 // Create new start symbol
 S_new = new_nonterminal()

 // New productions for Kleene star
 // S_new → S S_new | ε
 add_production(S_new, concatenate(S, S_new))
 add_production(S_new, epsilon) // epsilon production

 // Copy all productions from G
 FOR each production p in G.productions:
 add_production(p)

 RETURN new_grammar(S_new, productions)
END
